const text = $('LINE_Receive_Webhook').first().json.body.events[0].message.text;

// #delete
const tag = text.replace("#","").trim();

return [
{
json:{
tag:tag,
}
}
];

const searchTag = $items("Extract_Tag")[0].json.tag;

const rows = $input.all();

const results = rows.filter(row => {

  const tags = row.json.tags || "";

  return tags.toLowerCase().includes(searchTag.toLowerCase());

});

return results.slice(0,5);

const items = $input.all();

// Keep only the items that actually have data
const realItems = items.filter(item => item.json && (item.json.title || item.json.summary || (item.json.tags && item.json.tags.length)));

let payload;

if (realItems.length === 0) {
  payload = { message: "No matching notes were found.\\nSend #taglist to see a list of available tags." };
} else {
  let text = "Tag search results\n\n";

  realItems.forEach((item, i) => {
    text += (i + 1) + "\n";
    text += "Title:" + (item.json.title || "NoTitle") + "\n";
    text += "Summary:" + (item.json.summary || "NoSummary") + "\n";
    text += "tags:" + (Array.isArray(item.json.tags) ? item.json.tags.join(", ") : item.json.tags || "") + "\n\n";
  });

  payload = { message: text };
}

return [{ json: payload }];

const item = $input.first();

// Restore binary
item.binary = $node["LINE_Download_ImageContent"].binary;

return [item];

const rows = $input.all();

let tagSet = new Set();

for (const item of rows) {

  const tags = item.json.tags || "";

  tags.split(",")
    .map(t => t.trim())
    .filter(t => t !== "")
    .forEach(t => tagSet.add(t));

}

const tagList = Array.from(tagSet).sort();

return [
{
json:{
tagList: tagList,
tagText: tagList.join("\\n")
}
}
];
